SELECT * FROM monthly_expenses


        AND year = #{year}



        AND month = #{month}



        AND monthly_total LIKE CONCAT('%', #{monthlyTotal}, '%')



        AND (
        year LIKE CONCAT('%', #{key}, '%')  -- 年份模糊匹配key
        OR month LIKE CONCAT('%', #{key}, '%')  -- 月份模糊匹配key
        OR monthly_total LIKE CONCAT('%', #{key}, '%')  -- 金额模糊匹配key
        )


ORDER BY year DESC, month DESC
